import { isEqual } from 'lodash-es';
import { type Context } from 'react';

import { Store, useStoreSelector } from '@dynatrace/strato-components/core';

import { MapStore } from './map-store.context.js';
import type { MapState } from '../types/state.js';

export const useSelector = <O>(selector: (state: MapState) => O): O =>
  useStoreSelector(MapStore as Context<Store<MapState>>, selector, isEqual);

export const useMapSelectionState = () =>
  useSelector(({ selection }: MapState) => selection);

export const useMapTooltipLocationState = () =>
  useSelector(({ tooltip }: MapState) => tooltip.location);

export const useMapTooltipHoveredLayerIdState = () =>
  useSelector(({ tooltip }: MapState) => tooltip.hoveredLayerId);

export const useMapOverlayState = () =>
  useSelector(({ overlay }: MapState) => overlay);

export const useMapZoomState = () => useSelector(({ zoom }: MapState) => zoom);
